terraform:
resource "azurerm_storage_account" "public" {
  name                              = "publicingress01"
  location                          = "westeurope"
  resource_group_name               = "rg-public"
  account_tier                      = "Standard"
  account_replication_type          = "LRS"
  min_tls_version                   = "TLS1_2"
  public_network_access_enabled     = true
  infrastructure_encryption_enabled = true
  identity {
    type = "SystemAssigned"
  }
  tags = {
    project     = "archmorph"
    environment = "dev"
    managed_by  = "archmorph"
  }
  access_key = "plain-secret-value"
}

resource "azurerm_key_vault" "main" {
  name                          = "kvpublicingress01"
  location                      = "westeurope"
  resource_group_name           = "rg-public"
  tenant_id                     = "00000000-0000-0000-0000-000000000000"
  sku_name                      = "standard"
  public_network_access_enabled = true
}

resource "azurerm_monitor_diagnostic_setting" "storage" {
  name               = "diag-public-storage"
  target_resource_id = azurerm_storage_account.public.id
}

bicep:
var tags = {
  project: 'archmorph'
  environment: 'dev'
  managedBy: 'archmorph'
}

resource identity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: 'id-public-ingress'
  location: 'westeurope'
  tags: tags
}

resource keyVault 'Microsoft.KeyVault/vaults@2023-07-01' = {
  name: 'kv-public-ingress'
  location: 'westeurope'
  properties: {
    tenantId: '00000000-0000-0000-0000-000000000000'
    sku: {
      family: 'A'
      name: 'standard'
    }
    publicNetworkAccess: 'Enabled'
  }
  tags: tags
}

resource storage 'Microsoft.Storage/storageAccounts@2023-05-01' = {
  name: 'stpublicingress01'
  location: 'westeurope'
  sku: {
    name: 'Standard_LRS'
  }
  kind: 'StorageV2'
  identity: {
    type: 'SystemAssigned'
  }
  properties: {
    minimumTlsVersion: '1.2'
    publicNetworkAccess: 'Enabled'
    accessKey: 'plain-secret-value'
  }
  tags: tags
}

resource storageDiag 'Microsoft.Insights/diagnosticSettings@2021-05-01-preview' = {
  name: 'diag-public-storage'
  scope: storage
  properties: {
    logs: []
    metrics: []
  }
}
